INSERT INTO public.standard_groups_resource (created_at, name, short_name, description, points, pass_points, active, id, generated, mcp) VALUES ('2026-01-05T00:11:16.001501+00:00', 'Clarity and Structure', 'Clarity', 'Assesses clarity, organization, and structural consistency of prompts and instructions.', 5, 4, true, 'b1300000-0000-0000-0000-000000000001', false, false) ON CONFLICT (id) DO NOTHING;
