INSERT INTO public.standard_groups_resource (created_at, name, short_name, description, points, pass_points, active, id, generated, mcp) VALUES ('2026-01-05T00:11:16.001501+00:00', 'Tool Usage and Accuracy', 'Tool Usage', 'Measures correct tool selection and proper tool call execution.', 5, 4, true, 'b1100000-0000-0000-0000-000000000001', false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.standards_resource (created_at, name, description, points, id, standard_group_id, active, generated, mcp) VALUES ('2026-01-05T00:11:16.001501+00:00', 'Excellent', 'Perfect tool selection and execution. Uses correct tool (prompt vs instruct) for each scenario. All tool calls properly formatted and complete.', 5, 'b1110000-0000-0000-0000-000000000001', 'b1100000-0000-0000-0000-000000000001', true, false, false) ON CONFLICT (id) DO NOTHING;
